n_values = [15, 9, 10, 7]

for n in n_values:
    if n % 3 == 0 and n % 5 == 0:
        print("FizzBuzz")
    elif n % 3 == 0:
        print("Fizz")
    elif n % 5 == 0:
        print("Buzz")
    else:
        print(n)

people = [
    {"name": "Alice", "age": 8, "weekday": True},
    {"name": "Bob", "age": 30, "weekday": False},
    {"name": "Carol", "age": 70, "weekday": True},
]

for person in people:
    age = person["age"]
    if age < 12:
        price = 5
    elif age >= 65:
        price = 7
    else:
        price = 12
    if not person["weekday"]:
        price += 2
    print(f"{person['name']}: ${price}")

secret = 42
guesses = [20, 55, 38, 42, 99]
index = 0

while index < len(guesses):
    guess = guesses[index]
    if guess < secret:
        print(f"Guess {guess}: Too low")
    elif guess > secret:
        print(f"Guess {guess}: Too high")
    else:
        print(f"Guess {guess}: Correct!")
        break
    index += 1

numbers = [64, 48]

for n in numbers:
    original = n
    while n > 1:
        if n % 2 != 0:
            break
        n //= 2
    if n == 1:
        print(f"{original} is a power of 2")
    else:
        print(f"{original} is NOT a power of 2")

