names = ["Alice", "Bob", "Carol"]
subjects = ["Math", "Science", "English"]
scores = [95, 42, 78]

for name, subject, score in zip(names, subjects, scores):
    if score >= 90:
        status = "Pass with Distinction"
    elif score >= 50:
        status = "Pass"
    else:
        status = "Fail"
    print(f"{name} - {subject}: {score} ({status})")

